"""
benchmark_sweep/clean_sweep_csv.py
------------------------------------
One-time cleanup script. Removes local_* columns from dataset_sweep.csv
and clears evaluation-phase columns (tier*_correct, label, label_encoded).

Run ONCE before resuming the clean sweep.
"""
import csv
from pathlib import Path

WORKSPACE = Path(__file__).resolve().parent.parent
SRC  = WORKSPACE / "data_builder" / "dataset_sweep.csv"
DST  = WORKSPACE / "data_builder" / "dataset_sweep.csv"

# Columns generated by the OLD sweep that must be removed
REMOVE_COLS = {"local_response", "local_correct"}

# Columns that belong to the evaluation phase — reset to empty
EVAL_COLS = {"tier1_correct", "tier2_correct", "tier3_correct", "label", "label_encoded"}

print(f"Reading {SRC}...")
with open(SRC, "r", encoding="utf-8", newline="") as f:
    reader     = csv.DictReader(f)
    old_fields = list(reader.fieldnames)
    rows       = [dict(r) for r in reader]

# Build new fieldnames (drop local_* cols)
new_fields = [c for c in old_fields if c not in REMOVE_COLS]

# Clean rows
for row in rows:
    # Remove local_* columns
    for col in REMOVE_COLS:
        row.pop(col, None)
    # Clear evaluation columns (reset to blank)
    for col in EVAL_COLS:
        if col in row:
            row[col] = ""

print(f"Removed columns: {REMOVE_COLS & set(old_fields)}")
print(f"Cleared columns: {EVAL_COLS & set(old_fields)}")
print(f"New field count: {len(new_fields)} (was {len(old_fields)})")

rows_with_t3 = sum(1 for r in rows if str(r.get("tier3_response", "")).strip())
print(f"Rows with tier3_response filled (already swept): {rows_with_t3}/{len(rows)}")

print(f"Writing cleaned CSV to {DST}...")
with open(DST, "w", encoding="utf-8", newline="") as f:
    writer = csv.DictWriter(f, fieldnames=new_fields)
    writer.writeheader()
    writer.writerows(rows)

print("Done.")
